
<map>
  <node ID="root" TEXT="世界观（第3版）">
    <node TEXT="基础命题" ID="1Z7GhAc8pH" _mubu_text="%3Cspan%3E%E5%9F%BA%E7%A1%80%E5%91%BD%E9%A2%98%3C/span%3E" STYLE="bubble" POSITION="right">
      <node TEXT="世界观" ID="fXojfStBkh" _mubu_text="%3Cspan%3E%E4%B8%96%E7%95%8C%E8%A7%82%3C/span%3E" STYLE="fork">
        <node TEXT="观点" ID="qDVAWCptZF" _mubu_text="%3Cspan%3E%E8%A7%82%E7%82%B9%3C/span%3E" STYLE="fork">
          <node TEXT="简短描述：世界观指的是一个观点体系，其中不同观点如同拼图的一块块拼板一样相互连接。" ID="Pbdjuay4b0" _mubu_text="%3Cspan%3E%E7%AE%80%E7%9F%AD%E6%8F%8F%E8%BF%B0%EF%BC%9A%E4%B8%96%E7%95%8C%E8%A7%82%E6%8C%87%E7%9A%84%E6%98%AF%E4%B8%80%E4%B8%AA%3C/span%3E%3Cspan%20class=%22%20text-color-red%22%3E%E8%A7%82%E7%82%B9%E4%BD%93%E7%B3%BB%3C/span%3E%3Cspan%3E%EF%BC%8C%E5%85%B6%E4%B8%AD%E4%B8%8D%E5%90%8C%E8%A7%82%E7%82%B9%E5%A6%82%E5%90%8C%E6%8B%BC%E5%9B%BE%E7%9A%84%E4%B8%80%E5%9D%97%E5%9D%97%E6%8B%BC%E6%9D%BF%E4%B8%80%E6%A0%B7%E7%9B%B8%E4%BA%92%E8%BF%9E%E6%8E%A5%E3%80%82%3C/span%3E" STYLE="fork">
            <node TEXT="本书中的世界观：这些由一群人共同持有的观点像每个人自己秉持的观点一样，拼合在一起，形成一个环环相扣、具有一致性和稳定性的观点体系。" ID="KDeC4RQivb" _mubu_text="%3Cspan%20class=%22bold%22%3E%E6%9C%AC%E4%B9%A6%E4%B8%AD%E7%9A%84%E4%B8%96%E7%95%8C%E8%A7%82%EF%BC%9A%E8%BF%99%E4%BA%9B%E7%94%B1%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E4%B8%80%E7%BE%A4%E4%BA%BA%3C/span%3E%3Cspan%20class=%22bold%22%3E%E5%85%B1%E5%90%8C%E6%8C%81%E6%9C%89%E7%9A%84%E8%A7%82%E7%82%B9%E5%83%8F%E6%AF%8F%E4%B8%AA%E4%BA%BA%E8%87%AA%E5%B7%B1%E7%A7%89%E6%8C%81%E7%9A%84%E8%A7%82%E7%82%B9%E4%B8%80%E6%A0%B7%EF%BC%8C%E6%8B%BC%E5%90%88%E5%9C%A8%E4%B8%80%E8%B5%B7%EF%BC%8C%E5%BD%A2%E6%88%90%E4%B8%80%E4%B8%AA%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E7%8E%AF%E7%8E%AF%E7%9B%B8%E6%89%A3%E3%80%81%E5%85%B7%E6%9C%89%E4%B8%80%E8%87%B4%E6%80%A7%E5%92%8C%E7%A8%B3%E5%AE%9A%E6%80%A7%E7%9A%84%E8%A7%82%E7%82%B9%E4%BD%93%E7%B3%BB%E3%80%82%3C/span%3E" STYLE="fork"/>
          </node>
          <node TEXT="亚里士多德的观点和世界观" ID="5ozLK0sHeF" _mubu_text="%3Cspan%3E%E4%BA%9A%E9%87%8C%E5%A3%AB%E5%A4%9A%E5%BE%B7%E7%9A%84%E8%A7%82%E7%82%B9%E5%92%8C%E4%B8%96%E7%95%8C%E8%A7%82%3C/span%3E" STYLE="fork">
            <node TEXT="观点：1. 地球位于宇宙的中心……" ID="icld11BVN8" _mubu_text="%3Cspan%3E%E8%A7%82%E7%82%B9%EF%BC%9A1.%20%E5%9C%B0%E7%90%83%E4%BD%8D%E4%BA%8E%E5%AE%87%E5%AE%99%E7%9A%84%E4%B8%AD%E5%BF%83%E2%80%A6%E2%80%A6%3C/span%3E" STYLE="fork"/>
            <node TEXT="亚里士多德的这些观点并非不同观点的随机集合，而是组成了一个相互关联环环相扣的观点体系。" ID="XUEIUDof8M" _mubu_text="%3Cspan%3E%E4%BA%9A%E9%87%8C%E5%A3%AB%E5%A4%9A%E5%BE%B7%E7%9A%84%E8%BF%99%E4%BA%9B%E8%A7%82%E7%82%B9%E5%B9%B6%E9%9D%9E%E4%B8%8D%E5%90%8C%E8%A7%82%E7%82%B9%E7%9A%84%E9%9A%8F%E6%9C%BA%E9%9B%86%E5%90%88%EF%BC%8C%E8%80%8C%E6%98%AF%E7%BB%84%E6%88%90%E4%BA%86%E4%B8%80%E4%B8%AA%E7%9B%B8%E4%BA%92%E5%85%B3%E8%81%94%E7%8E%AF%E7%8E%AF%E7%9B%B8%E6%89%A3%E7%9A%84%E8%A7%82%E7%82%B9%E4%BD%93%E7%B3%BB%E3%80%82%3C/span%3E" STYLE="fork"/>
            <node TEXT="在一副拼图中，核心拼板和外围拼板存在一些不同点。" ID="r4zx7OuNR6" _mubu_text="%3Cspan%20class=%22bold%22%3E%E5%9C%A8%E4%B8%80%E5%89%AF%E6%8B%BC%E5%9B%BE%E4%B8%AD%EF%BC%8C%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E6%A0%B8%E5%BF%83%3C/span%3E%3Cspan%20class=%22bold%22%3E%E6%8B%BC%E6%9D%BF%E5%92%8C%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E5%A4%96%E5%9B%B4%3C/span%3E%3Cspan%20class=%22bold%22%3E%E6%8B%BC%E6%9D%BF%E5%AD%98%E5%9C%A8%E4%B8%80%E4%BA%9B%E4%B8%8D%E5%90%8C%E7%82%B9%E3%80%82%3C/span%3E" STYLE="fork">
              <node TEXT="外围观点：一个观点如果即使本身发生变化，也不会让其所在的观点体系产生实质性改变" ID="ksgG6YrLAR" _mubu_text="%3Cspan%3E%E5%A4%96%E5%9B%B4%E8%A7%82%E7%82%B9%EF%BC%9A%E4%B8%80%E4%B8%AA%E8%A7%82%E7%82%B9%E5%A6%82%E6%9E%9C%E5%8D%B3%E4%BD%BF%E6%9C%AC%E8%BA%AB%E5%8F%91%E7%94%9F%E5%8F%98%E5%8C%96%EF%BC%8C%E4%B9%9F%E4%B8%8D%E4%BC%9A%E8%AE%A9%E5%85%B6%E6%89%80%E5%9C%A8%E7%9A%84%E8%A7%82%E7%82%B9%E4%BD%93%E7%B3%BB%E4%BA%A7%E7%94%9F%E5%AE%9E%E8%B4%A8%E6%80%A7%E6%94%B9%E5%8F%98%3C/span%3E" STYLE="fork"/>
              <node TEXT="核心观点：不是因为对它深信不疑，而是因为如果把它去掉或替换掉，那么与她相关联的观点都要发生重大变化，而这反过来又会导致几乎整个观点体系的变化。" ID="oRZV1ALXy4" _mubu_text="%3Cspan%3E%E6%A0%B8%E5%BF%83%E8%A7%82%E7%82%B9%EF%BC%9A%E4%B8%8D%E6%98%AF%E5%9B%A0%E4%B8%BA%E5%AF%B9%E5%AE%83%E6%B7%B1%E4%BF%A1%E4%B8%8D%E7%96%91%EF%BC%8C%E8%80%8C%E6%98%AF%E5%9B%A0%E4%B8%BA%3C/span%3E%3Cspan%20class=%22%20text-color-red%22%3E%E5%A6%82%E6%9E%9C%E6%8A%8A%E5%AE%83%E5%8E%BB%E6%8E%89%E6%88%96%E6%9B%BF%E6%8D%A2%E6%8E%89%EF%BC%8C%E9%82%A3%E4%B9%88%E4%B8%8E%E5%A5%B9%E7%9B%B8%E5%85%B3%E8%81%94%E7%9A%84%E8%A7%82%E7%82%B9%E9%83%BD%E8%A6%81%E5%8F%91%E7%94%9F%E9%87%8D%E5%A4%A7%E5%8F%98%E5%8C%96%3C/span%3E%3Cspan%3E%EF%BC%8C%E8%80%8C%E8%BF%99%E5%8F%8D%E8%BF%87%E6%9D%A5%E5%8F%88%E4%BC%9A%E5%AF%BC%E8%87%B4%E5%87%A0%E4%B9%8E%E6%95%B4%E4%B8%AA%E8%A7%82%E7%82%B9%E4%BD%93%E7%B3%BB%E7%9A%84%E5%8F%98%E5%8C%96%E3%80%82%3C/span%3E" STYLE="fork"/>
            </node>
          </node>
        </node>
        <node TEXT="证据" ID="jSewEZ8RuD" _mubu_text="%3Cspan%3E%E8%AF%81%E6%8D%AE%3C/span%3E" STYLE="fork">
          <node TEXT="我们只能为我们所秉持的极小一部分观点拿出直接证据。对于我们的大多数观点（也许是几乎所有观点）来说，我们之所以秉持这些观点，主要是因为它们可以与我们的世界观拼合在一起。" ID="0hcU9iB05m" _mubu_text="%3Cspan%20class=%22bold%22%3E%E6%88%91%E4%BB%AC%E5%8F%AA%E8%83%BD%E4%B8%BA%E6%88%91%E4%BB%AC%E6%89%80%E7%A7%89%E6%8C%81%E7%9A%84%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E6%9E%81%E5%B0%8F%E4%B8%80%E9%83%A8%E5%88%86%E8%A7%82%E7%82%B9%3C/span%3E%3Cspan%20class=%22bold%22%3E%E6%8B%BF%E5%87%BA%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E7%9B%B4%E6%8E%A5%E8%AF%81%E6%8D%AE%3C/span%3E%3Cspan%20class=%22bold%22%3E%E3%80%82%E5%AF%B9%E4%BA%8E%E6%88%91%E4%BB%AC%E7%9A%84%E5%A4%A7%E5%A4%9A%E6%95%B0%E8%A7%82%E7%82%B9%EF%BC%88%E4%B9%9F%E8%AE%B8%E6%98%AF%E5%87%A0%E4%B9%8E%E6%89%80%E6%9C%89%E8%A7%82%E7%82%B9%EF%BC%89%E6%9D%A5%E8%AF%B4%EF%BC%8C%E6%88%91%E4%BB%AC%E4%B9%8B%E6%89%80%E4%BB%A5%E7%A7%89%E6%8C%81%E8%BF%99%E4%BA%9B%E8%A7%82%E7%82%B9%EF%BC%8C%E4%B8%BB%E8%A6%81%E6%98%AF%E5%9B%A0%E4%B8%BA%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E5%AE%83%E4%BB%AC%E5%8F%AF%E4%BB%A5%E4%B8%8E%E6%88%91%E4%BB%AC%E7%9A%84%E4%B8%96%E7%95%8C%E8%A7%82%E6%8B%BC%E5%90%88%E5%9C%A8%E4%B8%80%E8%B5%B7%E3%80%82%3C/span%3E" STYLE="fork"/>
        </node>
        <node TEXT="常识" ID="9jP0orpnO9" _mubu_text="%3Cspan%3E%E5%B8%B8%E8%AF%86%3C/span%3E" STYLE="fork">
          <node TEXT="我们目前接受的是牛顿世界观，其中大多数观点似乎都变成了常识，但其中大多数尽管我们大多数人都认同，但它们并不是我们通过常识或一般经验就能得到的" ID="bCMgw1DmaD" _mubu_text="%3Cspan%3E%E6%88%91%E4%BB%AC%E7%9B%AE%E5%89%8D%E6%8E%A5%E5%8F%97%E7%9A%84%E6%98%AF%E7%89%9B%E9%A1%BF%E4%B8%96%E7%95%8C%E8%A7%82%EF%BC%8C%E5%85%B6%E4%B8%AD%E5%A4%A7%E5%A4%9A%E6%95%B0%E8%A7%82%E7%82%B9%E4%BC%BC%E4%B9%8E%E9%83%BD%E5%8F%98%E6%88%90%E4%BA%86%E5%B8%B8%E8%AF%86%EF%BC%8C%E4%BD%86%E5%85%B6%E4%B8%AD%3C/span%3E%3Cspan%20class=%22bold%22%3E%E5%A4%A7%E5%A4%9A%E6%95%B0%E5%B0%BD%E7%AE%A1%E6%88%91%E4%BB%AC%E5%A4%A7%E5%A4%9A%E6%95%B0%E4%BA%BA%E9%83%BD%E8%AE%A4%E5%90%8C%EF%BC%8C%E4%BD%86%E5%AE%83%E4%BB%AC%E5%B9%B6%E4%B8%8D%E6%98%AF%E6%88%91%E4%BB%AC%E9%80%9A%E8%BF%87%E5%B8%B8%E8%AF%86%E6%88%96%E4%B8%80%E8%88%AC%E7%BB%8F%E9%AA%8C%E5%B0%B1%E8%83%BD%E5%BE%97%E5%88%B0%E7%9A%84%3C/span%3E" STYLE="fork"/>
          <node TEXT="从任何一个世界观自身的角度来看，这一世界观的观点都显而易见是正确的" ID="4igay8pT4z" _mubu_text="%3Cspan%3E%E4%BB%8E%E4%BB%BB%E4%BD%95%E4%B8%80%E4%B8%AA%E4%B8%96%E7%95%8C%E8%A7%82%E8%87%AA%E8%BA%AB%E7%9A%84%E8%A7%92%E5%BA%A6%E6%9D%A5%E7%9C%8B%EF%BC%8C%E8%BF%99%E4%B8%80%E4%B8%96%E7%95%8C%E8%A7%82%E7%9A%84%E8%A7%82%E7%82%B9%E9%83%BD%E6%98%BE%E8%80%8C%E6%98%93%E8%A7%81%E6%98%AF%E6%AD%A3%E7%A1%AE%E7%9A%84%3C/span%3E" STYLE="fork"/>
          <node TEXT="毫无疑问，我们的某些观点会被证明是错误的。但我所提出的问题是：我们看待这个世界的整个方法会不会被证明是错误的，就像亚里士多德的世界观一样，被证明是一个错误的拼图？" ID="1fdz2UVlC9" _mubu_text="%3Cspan%3E%E6%AF%AB%E6%97%A0%E7%96%91%E9%97%AE%EF%BC%8C%E6%88%91%E4%BB%AC%E7%9A%84%E6%9F%90%E4%BA%9B%E8%A7%82%E7%82%B9%E4%BC%9A%E8%A2%AB%E8%AF%81%E6%98%8E%E6%98%AF%E9%94%99%E8%AF%AF%E7%9A%84%E3%80%82%E4%BD%86%E6%88%91%E6%89%80%E6%8F%90%E5%87%BA%E7%9A%84%E9%97%AE%E9%A2%98%E6%98%AF%EF%BC%9A%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E6%88%91%E4%BB%AC%E7%9C%8B%E5%BE%85%E8%BF%99%E4%B8%AA%E4%B8%96%E7%95%8C%E7%9A%84%E6%95%B4%E4%B8%AA%E6%96%B9%E6%B3%95%3C/span%3E%3Cspan%3E%E4%BC%9A%E4%B8%8D%E4%BC%9A%E8%A2%AB%E8%AF%81%E6%98%8E%E6%98%AF%E9%94%99%E8%AF%AF%E7%9A%84%EF%BC%8C%E5%B0%B1%E5%83%8F%E4%BA%9A%E9%87%8C%E5%A3%AB%E5%A4%9A%E5%BE%B7%E7%9A%84%E4%B8%96%E7%95%8C%E8%A7%82%E4%B8%80%E6%A0%B7%EF%BC%8C%E8%A2%AB%E8%AF%81%E6%98%8E%E6%98%AF%E4%B8%80%E4%B8%AA%E9%94%99%E8%AF%AF%E7%9A%84%E6%8B%BC%E5%9B%BE%EF%BC%9F%3C/span%3E" STYLE="fork"/>
        </node>
      </node>
      <node TEXT="真理" ID="6oRXSRMUE1" _mubu_text="%3Cspan%3E%E7%9C%9F%E7%90%86%3C/span%3E" STYLE="fork">
        <node TEXT="基本命题" ID="IQwaWRrL8t" _mubu_text="%3Cspan%3E%E5%9F%BA%E6%9C%AC%E5%91%BD%E9%A2%98%3C/span%3E" STYLE="fork">
          <node TEXT="什么是真理（真的观点）？" ID="KZjUnvHGPD" _mubu_text="%3Cspan%20class=%22bold%20text-color-red%22%3E%E4%BB%80%E4%B9%88%E6%98%AF%E7%9C%9F%E7%90%86%3C/span%3E%3Cspan%20class=%22%20text-color-red%22%3E%EF%BC%88%E7%9C%9F%E7%9A%84%E8%A7%82%E7%82%B9%EF%BC%89%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%EF%BC%9F%3C/span%3E" STYLE="fork">
            <node TEXT="被证实的或者不存在争议的事实/被认为是真实的事情" ID="Z2CO6TltkV" _mubu_text="%3Cspan%20class=%22strikethrough%22%3E%E8%A2%AB%E8%AF%81%E5%AE%9E%E7%9A%84%E6%88%96%E8%80%85%E4%B8%8D%E5%AD%98%E5%9C%A8%E4%BA%89%E8%AE%AE%E7%9A%84%E4%BA%8B%E5%AE%9E/%E8%A2%AB%E8%AE%A4%E4%B8%BA%E6%98%AF%E7%9C%9F%E5%AE%9E%E7%9A%84%E4%BA%8B%E6%83%85%3C/span%3E" STYLE="fork"/>
            <node TEXT="历史包含了大量事件，比如战争、暗杀……，它们之所以发生，大多是因为人们深信某些特定的观点是真的，而其他观点是假的。" ID="XOhIJ6ft9Q" _mubu_text="%3Cspan%3E%E5%8E%86%E5%8F%B2%E5%8C%85%E5%90%AB%E4%BA%86%E5%A4%A7%E9%87%8F%E4%BA%8B%E4%BB%B6%EF%BC%8C%E6%AF%94%E5%A6%82%E6%88%98%E4%BA%89%E3%80%81%E6%9A%97%E6%9D%80%E2%80%A6%E2%80%A6%EF%BC%8C%E5%AE%83%E4%BB%AC%E4%B9%8B%E6%89%80%E4%BB%A5%E5%8F%91%E7%94%9F%EF%BC%8C%E5%A4%A7%E5%A4%9A%E6%98%AF%E5%9B%A0%E4%B8%BA%E4%BA%BA%E4%BB%AC%E6%B7%B1%E4%BF%A1%E6%9F%90%E4%BA%9B%E7%89%B9%E5%AE%9A%E7%9A%84%E8%A7%82%E7%82%B9%E6%98%AF%E7%9C%9F%E7%9A%84%EF%BC%8C%E8%80%8C%E5%85%B6%E4%BB%96%E8%A7%82%E7%82%B9%E6%98%AF%E5%81%87%E7%9A%84%E3%80%82%3C/span%3E" STYLE="fork"/>
            <node TEXT="本章主要目标之一是对真理进行讨论，但不会给出确定答复（因为人们对这个问题的争论至少可以追溯到哲学和科学的诞生之日，并且仍没有达成共识）。但是关于真理还是出现了一些标准性的观点，我们至少可以大致了解这些标准性的观点。" ID="eBRm20yH6h" _mubu_text="%3Cspan%3E%E6%9C%AC%E7%AB%A0%E4%B8%BB%E8%A6%81%E7%9B%AE%E6%A0%87%E4%B9%8B%E4%B8%80%E6%98%AF%E5%AF%B9%E7%9C%9F%E7%90%86%E8%BF%9B%E8%A1%8C%E8%AE%A8%E8%AE%BA%EF%BC%8C%E4%BD%86%3C/span%3E%3Cspan%20class=%22bold%22%3E%E4%B8%8D%E4%BC%9A%E7%BB%99%E5%87%BA%E7%A1%AE%E5%AE%9A%E7%AD%94%E5%A4%8D%3C/span%3E%3Cspan%3E%EF%BC%88%E5%9B%A0%E4%B8%BA%E4%BA%BA%E4%BB%AC%E5%AF%B9%E8%BF%99%E4%B8%AA%E9%97%AE%E9%A2%98%E7%9A%84%E4%BA%89%E8%AE%BA%E8%87%B3%E5%B0%91%E5%8F%AF%E4%BB%A5%E8%BF%BD%E6%BA%AF%E5%88%B0%E5%93%B2%E5%AD%A6%E5%92%8C%E7%A7%91%E5%AD%A6%E7%9A%84%E8%AF%9E%E7%94%9F%E4%B9%8B%E6%97%A5%EF%BC%8C%E5%B9%B6%E4%B8%94%3C/span%3E%3Cspan%20class=%22bold%22%3E%E4%BB%8D%E6%B2%A1%E6%9C%89%E8%BE%BE%E6%88%90%E5%85%B1%E8%AF%86%3C/span%3E%3Cspan%3E%EF%BC%89%E3%80%82%E4%BD%86%E6%98%AF%E5%85%B3%E4%BA%8E%E7%9C%9F%E7%90%86%E8%BF%98%E6%98%AF%E5%87%BA%E7%8E%B0%E4%BA%86%E4%B8%80%E4%BA%9B%3C/span%3E%3Cspan%20class=%22bold%22%3E%E6%A0%87%E5%87%86%E6%80%A7%E7%9A%84%E8%A7%82%E7%82%B9%3C/span%3E%3Cspan%3E%EF%BC%8C%E6%88%91%E4%BB%AC%E8%87%B3%E5%B0%91%E5%8F%AF%E4%BB%A5%E5%A4%A7%E8%87%B4%E4%BA%86%E8%A7%A3%E8%BF%99%E4%BA%9B%E6%A0%87%E5%87%86%E6%80%A7%E7%9A%84%E8%A7%82%E7%82%B9%E3%80%82%3C/span%3E" STYLE="fork"/>
          </node>
        </node>
        <node TEXT="澄清" ID="BAQ5OK7yLY" _mubu_text="%3Cspan%3E%E6%BE%84%E6%B8%85%3C/span%3E" STYLE="fork">
          <node TEXT="什么是真理→什么决定了一个观点为真≠真理的特点(认识论)" ID="vY9UNkVrxe" _mubu_text="%3Cspan%3E%E4%BB%80%E4%B9%88%E6%98%AF%E7%9C%9F%E7%90%86%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E2%86%92%3C/span%3E%3Cspan%3E%E4%BB%80%E4%B9%88%E5%86%B3%E5%AE%9A%E4%BA%86%E4%B8%80%E4%B8%AA%E8%A7%82%E7%82%B9%E4%B8%BA%E7%9C%9F%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E2%89%A0%3C/span%3E%3Cspan%3E%E7%9C%9F%E7%90%86%E7%9A%84%E7%89%B9%E7%82%B9(%E8%AE%A4%E8%AF%86%E8%AE%BA)%3C/span%3E" STYLE="fork"/>
          <node TEXT="什么是真理？大量理论作为可能的答案可被划分为两类" ID="dP4azMdvaF" _mubu_text="%3Cspan%3E%E4%BB%80%E4%B9%88%E6%98%AF%E7%9C%9F%E7%90%86%EF%BC%9F%E5%A4%A7%E9%87%8F%E7%90%86%E8%AE%BA%E4%BD%9C%E4%B8%BA%E5%8F%AF%E8%83%BD%E7%9A%84%E7%AD%94%E6%A1%88%E5%8F%AF%E8%A2%AB%E5%88%92%E5%88%86%E4%B8%BA%E4%B8%A4%E7%B1%BB%3C/span%3E" STYLE="fork">
            <node TEXT="真理符合论" ID="4i55nc06cY" _mubu_text="%3Cspan%3E%E7%9C%9F%E7%90%86%E7%AC%A6%E5%90%88%E8%AE%BA%3C/span%3E" STYLE="fork">
              <node TEXT="概括：决定一个真的观点为真的因素是这个观点与独立、客观的现实相符合，决定一个假的观点为假的因素是这个观点没能与现实相符合。" ID="5D49Y5hEjT" _mubu_text="%3Cspan%20class=%22bold%22%3E%E6%A6%82%E6%8B%AC%EF%BC%9A%E5%86%B3%E5%AE%9A%E4%B8%80%E4%B8%AA%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E7%9C%9F%3C/span%3E%3Cspan%20class=%22bold%22%3E%E7%9A%84%E8%A7%82%E7%82%B9%E4%B8%BA%E7%9C%9F%E7%9A%84%E5%9B%A0%E7%B4%A0%E6%98%AF%E8%BF%99%E4%B8%AA%E8%A7%82%E7%82%B9%E4%B8%8E%E7%8B%AC%E7%AB%8B%E3%80%81%E5%AE%A2%E8%A7%82%E7%9A%84%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E7%8E%B0%E5%AE%9E%3C/span%3E%3Cspan%20class=%22bold%22%3E%E7%9B%B8%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E7%AC%A6%E5%90%88%3C/span%3E%3Cspan%20class=%22bold%22%3E%EF%BC%8C%E5%86%B3%E5%AE%9A%E4%B8%80%E4%B8%AA%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E5%81%87%3C/span%3E%3Cspan%20class=%22bold%22%3E%E7%9A%84%E8%A7%82%E7%82%B9%E4%B8%BA%E5%81%87%E7%9A%84%E5%9B%A0%E7%B4%A0%E6%98%AF%E8%BF%99%E4%B8%AA%E8%A7%82%E7%82%B9%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E6%B2%A1%E8%83%BD%E4%B8%8E%E7%8E%B0%E5%AE%9E%E7%9B%B8%E7%AC%A6%E5%90%88%3C/span%3E%3Cspan%20class=%22bold%22%3E%E3%80%82%3C/span%3E" STYLE="fork">
                <node TEXT="现实的释义有很多，要理解真理符合论，关键点是理解“现实”这个词是如何运用的" ID="iGtpJKibT3" _mubu_text="%3Cspan%3E%E7%8E%B0%E5%AE%9E%E7%9A%84%E9%87%8A%E4%B9%89%E6%9C%89%E5%BE%88%E5%A4%9A%EF%BC%8C%E8%A6%81%E7%90%86%E8%A7%A3%E7%9C%9F%E7%90%86%E7%AC%A6%E5%90%88%E8%AE%BA%EF%BC%8C%E5%85%B3%E9%94%AE%E7%82%B9%E6%98%AF%E7%90%86%E8%A7%A3%E2%80%9C%E7%8E%B0%E5%AE%9E%E2%80%9D%E8%BF%99%E4%B8%AA%E8%AF%8D%E6%98%AF%E5%A6%82%E4%BD%95%E8%BF%90%E7%94%A8%E7%9A%84%3C/span%3E" STYLE="fork"/>
                <node TEXT="现实：“真的”现实完全客观，独立于我们，通常不取决于大多数人是如何认为的。" ID="h7uU1NIs5Q" _mubu_text="%3Cspan%3E%E7%8E%B0%E5%AE%9E%EF%BC%9A%E2%80%9C%E7%9C%9F%E7%9A%84%E2%80%9D%E7%8E%B0%E5%AE%9E%E5%AE%8C%E5%85%A8%E5%AE%A2%E8%A7%82%EF%BC%8C%E7%8B%AC%E7%AB%8B%E4%BA%8E%E6%88%91%E4%BB%AC%EF%BC%8C%E9%80%9A%E5%B8%B8%E4%B8%8D%E5%8F%96%E5%86%B3%E4%BA%8E%E5%A4%A7%E5%A4%9A%E6%95%B0%E4%BA%BA%E6%98%AF%E5%A6%82%E4%BD%95%E8%AE%A4%E4%B8%BA%E7%9A%84%E3%80%82%3C/span%3E" STYLE="fork"/>
              </node>
              <node TEXT="问题和困惑" ID="JvkJExCJle" _mubu_text="%3Cspan%20class=%22bold%22%3E%E9%97%AE%E9%A2%98%E5%92%8C%E5%9B%B0%E6%83%91%3C/span%3E" STYLE="fork">
                <node TEXT="知觉表征论：感官为我们提供了外部世界各种物体的表征≠现实" ID="93AldIjqa1" _mubu_text="%3Cspan%20class=%22bold%20text-color-red%22%3E%E7%9F%A5%E8%A7%89%E8%A1%A8%E5%BE%81%E8%AE%BA%3C/span%3E%3Cspan%3E%EF%BC%9A%E6%84%9F%E5%AE%98%E4%B8%BA%E6%88%91%E4%BB%AC%E6%8F%90%E4%BE%9B%E4%BA%86%E5%A4%96%E9%83%A8%E4%B8%96%E7%95%8C%E5%90%84%E7%A7%8D%E7%89%A9%E4%BD%93%E7%9A%84%E8%A1%A8%E5%BE%81%3C/span%3E%3Cspan%20class=%22bold%22%3E%E2%89%A0%3C/span%3E%3Cspan%3E%E7%8E%B0%E5%AE%9E%3C/span%3E" STYLE="fork">
                  <node TEXT="→这个观点意味着我们每个人从某种意义上来说都是与这个世界隔绝的。更具体的说，我们没有办法确定自身感官所提供的表征是否准确。" ID="3aIeAyhzqb" _mubu_text="%3Cspan%20class=%22bold%22%3E%E2%86%92%3C/span%3E%3Cspan%3E%E8%BF%99%E4%B8%AA%E8%A7%82%E7%82%B9%E6%84%8F%E5%91%B3%E7%9D%80%E6%88%91%E4%BB%AC%E6%AF%8F%E4%B8%AA%E4%BA%BA%E4%BB%8E%E6%9F%90%E7%A7%8D%E6%84%8F%E4%B9%89%E4%B8%8A%E6%9D%A5%E8%AF%B4%E9%83%BD%E6%98%AF%E4%B8%8E%E8%BF%99%E4%B8%AA%E4%B8%96%E7%95%8C%E9%9A%94%E7%BB%9D%E7%9A%84%E3%80%82%E6%9B%B4%E5%85%B7%E4%BD%93%E7%9A%84%E8%AF%B4%EF%BC%8C%E6%88%91%E4%BB%AC%E6%B2%A1%E6%9C%89%E5%8A%9E%E6%B3%95%E7%A1%AE%E5%AE%9A%E8%87%AA%E8%BA%AB%E6%84%9F%E5%AE%98%E6%89%80%E6%8F%90%E4%BE%9B%E7%9A%84%E8%A1%A8%E5%BE%81%E6%98%AF%E5%90%A6%E5%87%86%E7%A1%AE%E3%80%82%3C/span%3E" STYLE="fork"/>
                  <node TEXT="因为所能运用的都在意识里，即使是用类似于触觉去评估视觉，那也是用一种表征去评估另一种表征，而与这个表征所代表的事物之间的对比并没有进行。我们根本没有办法确定现实到底是什么样子的。" ID="6sceWDXbzD" _mubu_text="%3Cspan%3E%E5%9B%A0%E4%B8%BA%3C/span%3E%3Cspan%20class=%22%20text-color-red%22%3E%E6%89%80%E8%83%BD%E8%BF%90%E7%94%A8%E7%9A%84%E9%83%BD%E5%9C%A8%E6%84%8F%E8%AF%86%E9%87%8C%3C/span%3E%3Cspan%3E%EF%BC%8C%E5%8D%B3%E4%BD%BF%E6%98%AF%E7%94%A8%E7%B1%BB%E4%BC%BC%E4%BA%8E%E8%A7%A6%E8%A7%89%E5%8E%BB%E8%AF%84%E4%BC%B0%E8%A7%86%E8%A7%89%EF%BC%8C%E9%82%A3%E4%B9%9F%E6%98%AF%E7%94%A8%E4%B8%80%E7%A7%8D%E8%A1%A8%E5%BE%81%E5%8E%BB%E8%AF%84%E4%BC%B0%E5%8F%A6%E4%B8%80%E7%A7%8D%E8%A1%A8%E5%BE%81%EF%BC%8C%E8%80%8C%3C/span%3E%3Cspan%20class=%22bold%20text-color-red%22%3E%E4%B8%8E%E8%BF%99%E4%B8%AA%E8%A1%A8%E5%BE%81%E6%89%80%E4%BB%A3%E8%A1%A8%E7%9A%84%E4%BA%8B%E7%89%A9%E4%B9%8B%E9%97%B4%E7%9A%84%E5%AF%B9%E6%AF%94%E5%B9%B6%E6%B2%A1%E6%9C%89%E8%BF%9B%E8%A1%8C%3C/span%3E%3Cspan%3E%E3%80%82%E6%88%91%E4%BB%AC%E6%A0%B9%E6%9C%AC%3C/span%3E%3Cspan%20class=%22%20text-color-red%22%3E%E6%B2%A1%E6%9C%89%E5%8A%9E%E6%B3%95%E7%A1%AE%E5%AE%9A%E7%8E%B0%E5%AE%9E%E5%88%B0%E5%BA%95%E6%98%AF%E4%BB%80%E4%B9%88%E6%A0%B7%E5%AD%90%3C/span%3E%3Cspan%3E%E7%9A%84%E3%80%82%3C/span%3E" STYLE="fork"/>
                </node>
                <node TEXT="是否存在我们可以完全确定的事物？" ID="ZhEVuNOWc8" _mubu_text="%3Cspan%20class=%22bold%22%3E%E6%98%AF%E5%90%A6%E5%AD%98%E5%9C%A8%E6%88%91%E4%BB%AC%E5%8F%AF%E4%BB%A5%E5%AE%8C%E5%85%A8%E7%A1%AE%E5%AE%9A%E7%9A%84%E4%BA%8B%E7%89%A9%EF%BC%9F%3C/span%3E" STYLE="fork">
                  <node TEXT="笛卡尔最初的目标之一就是找到一个绝对确定的、可以在其之上进行知识构建的基础。" ID="5G9JRcm2Zf" _mubu_text="%3Cspan%20class=%22bold%22%3E%E7%AC%9B%E5%8D%A1%E5%B0%94%E6%9C%80%E5%88%9D%E7%9A%84%E7%9B%AE%E6%A0%87%E4%B9%8B%E4%B8%80%E5%B0%B1%E6%98%AF%E6%89%BE%E5%88%B0%E4%B8%80%E4%B8%AA%E7%BB%9D%E5%AF%B9%E7%A1%AE%E5%AE%9A%E7%9A%84%E3%80%81%E5%8F%AF%E4%BB%A5%E5%9C%A8%E5%85%B6%E4%B9%8B%E4%B8%8A%E8%BF%9B%E8%A1%8C%E7%9F%A5%E8%AF%86%E6%9E%84%E5%BB%BA%E7%9A%84%E5%9F%BA%E7%A1%80%E3%80%82%3C/span%3E" STYLE="fork">
                    <node TEXT="他认为他找到了至少一个这样的观点：我思故我在。他确定他作为一个思维主体存在的观点" ID="H7bO0pPuES" _mubu_text="%3Cspan%20class=%22bold%22%3E%E4%BB%96%E8%AE%A4%E4%B8%BA%E4%BB%96%E6%89%BE%E5%88%B0%E4%BA%86%E8%87%B3%E5%B0%91%E4%B8%80%E4%B8%AA%E8%BF%99%E6%A0%B7%E7%9A%84%E8%A7%82%E7%82%B9%EF%BC%9A%E6%88%91%E6%80%9D%E6%95%85%E6%88%91%E5%9C%A8%E3%80%82%E4%BB%96%E7%A1%AE%E5%AE%9A%E4%BB%96%E4%BD%9C%E4%B8%BA%E4%B8%80%E4%B8%AA%E6%80%9D%E7%BB%B4%E4%B8%BB%E4%BD%93%E5%AD%98%E5%9C%A8%E7%9A%84%E8%A7%82%E7%82%B9%3C/span%3E" STYLE="fork"/>
                    <node TEXT="但是可以完全确定的观点非常少（可能只有一个），并且后来被证明，做这些观点所构成的基础太小了，人们无法在其上进行知识构建" ID="vgQEmW6f4k" _mubu_text="%3Cspan%20class=%22bold%22%3E%E4%BD%86%E6%98%AF%E5%8F%AF%E4%BB%A5%E5%AE%8C%E5%85%A8%E7%A1%AE%E5%AE%9A%E7%9A%84%E8%A7%82%E7%82%B9%E9%9D%9E%E5%B8%B8%E5%B0%91%EF%BC%88%E5%8F%AF%E8%83%BD%E5%8F%AA%E6%9C%89%E4%B8%80%E4%B8%AA%EF%BC%89%EF%BC%8C%E5%B9%B6%E4%B8%94%E5%90%8E%E6%9D%A5%E8%A2%AB%E8%AF%81%E6%98%8E%EF%BC%8C%E5%81%9A%E8%BF%99%E4%BA%9B%E8%A7%82%E7%82%B9%E6%89%80%E6%9E%84%E6%88%90%E7%9A%84%E5%9F%BA%E7%A1%80%E5%A4%AA%E5%B0%8F%E4%BA%86%EF%BC%8C%E4%BA%BA%E4%BB%AC%E6%97%A0%E6%B3%95%E5%9C%A8%E5%85%B6%E4%B8%8A%E8%BF%9B%E8%A1%8C%E7%9F%A5%E8%AF%86%E6%9E%84%E5%BB%BA%3C/span%3E" STYLE="fork"/>
                  </node>
                </node>
              </node>
            </node>
