              <node TEXT="种类：不同的融贯论之间的主要差异在于把谁的观点算在观点拼图里。" ID="rUmij65g6r" _mubu_text="%3Cspan%20class=%22bold%22%3E%E7%A7%8D%E7%B1%BB%EF%BC%9A%3C/span%3E%3Cspan%20class=%22%20text-color-red%22%3E%E4%B8%8D%E5%90%8C%E7%9A%84%E8%9E%8D%E8%B4%AF%E8%AE%BA%3C/span%3E%3Cspan%3E%E4%B9%8B%E9%97%B4%E7%9A%84%3C/span%3E%3Cspan%20class=%22%20text-color-red%22%3E%E4%B8%BB%E8%A6%81%E5%B7%AE%E5%BC%82%3C/span%3E%3Cspan%3E%E5%9C%A8%E4%BA%8E%E6%8A%8A%3C/span%3E%3Cspan%20class=%22%20text-color-red%22%3E%E8%B0%81%E7%9A%84%E8%A7%82%E7%82%B9%3C/span%3E%3Cspan%3E%E7%AE%97%E5%9C%A8%3C/span%3E%3Cspan%20class=%22%20text-color-red%22%3E%E8%A7%82%E7%82%B9%E6%8B%BC%E5%9B%BE%3C/span%3E%3Cspan%3E%E9%87%8C%E3%80%82%3C/span%3E" STYLE="fork">
                <node TEXT="个人主义融贯论" ID="Q90gwR69P2" _mubu_text="%3Cspan%3E%E4%B8%AA%E4%BA%BA%E4%B8%BB%E4%B9%89%E8%9E%8D%E8%B4%AF%E8%AE%BA%3C/span%3E" STYLE="fork">
                  <node TEXT="极端的“一切皆有可能”的相对主义" ID="eIRPNLJ1Pi" _mubu_text="%3Cspan%3E%E6%9E%81%E7%AB%AF%E7%9A%84%E2%80%9C%E4%B8%80%E5%88%87%E7%9A%86%E6%9C%89%E5%8F%AF%E8%83%BD%E2%80%9D%E7%9A%84%E7%9B%B8%E5%AF%B9%E4%B8%BB%E4%B9%89%3C/span%3E" STYLE="fork"/>
