                <node TEXT="团体融贯论" ID="UXfFGVvVN5" _mubu_text="%3Cspan%3E%E5%9B%A2%E4%BD%93%E8%9E%8D%E8%B4%AF%E8%AE%BA%3C/span%3E" STYLE="fork">
                  <node TEXT="1. 没有考虑一个群体可能秉持错误观点的可能性 2. 没有办法明确那些人可以算作群体的一份子 3. 对任何一个群体来说，都不存在一个由整个群体共同秉持的、具有一致性的观点集合。" ID="DM5CEtk8fH" _mubu_text="%3Cspan%3E1.%20%E6%B2%A1%E6%9C%89%E8%80%83%E8%99%91%E4%B8%80%E4%B8%AA%E7%BE%A4%E4%BD%93%E5%8F%AF%E8%83%BD%E7%A7%89%E6%8C%81%E9%94%99%E8%AF%AF%E8%A7%82%E7%82%B9%E7%9A%84%E5%8F%AF%E8%83%BD%E6%80%A7%202.%20%E6%B2%A1%E6%9C%89%E5%8A%9E%E6%B3%95%E6%98%8E%E7%A1%AE%E9%82%A3%E4%BA%9B%E4%BA%BA%E5%8F%AF%E4%BB%A5%E7%AE%97%E4%BD%9C%E7%BE%A4%E4%BD%93%E7%9A%84%E4%B8%80%E4%BB%BD%E5%AD%90%203.%20%E5%AF%B9%E4%BB%BB%E4%BD%95%E4%B8%80%E4%B8%AA%E7%BE%A4%E4%BD%93%E6%9D%A5%E8%AF%B4%EF%BC%8C%E9%83%BD%E4%B8%8D%E5%AD%98%E5%9C%A8%E4%B8%80%E4%B8%AA%E7%94%B1%E6%95%B4%E4%B8%AA%E7%BE%A4%E4%BD%93%E5%85%B1%E5%90%8C%E7%A7%89%E6%8C%81%E7%9A%84%E3%80%81%E5%85%B7%E6%9C%89%E4%B8%80%E8%87%B4%E6%80%A7%E7%9A%84%E8%A7%82%E7%82%B9%E9%9B%86%E5%90%88%E3%80%82%3C/span%3E" STYLE="fork"/>
                </node>
              </node>
            </node>
          </node>
        </node>
