      <node TEXT="经验事实和哲学性/概念性事实" ID="jTUO6vcwhu" _mubu_text="%3Cspan%3E%E7%BB%8F%E9%AA%8C%E4%BA%8B%E5%AE%9E%E5%92%8C%E5%93%B2%E5%AD%A6%E6%80%A7/%E6%A6%82%E5%BF%B5%E6%80%A7%E4%BA%8B%E5%AE%9E%3C/span%3E" STYLE="fork">
        <node TEXT="经验事实：一类以观察为基础的事实。" ID="hG1fICDh1b" _mubu_text="%3Cspan%20class=%22bold%22%3E%E7%BB%8F%E9%AA%8C%E4%BA%8B%E5%AE%9E%EF%BC%9A%3C/span%3E%3Cspan%3E%E4%B8%80%E7%B1%BB%E4%BB%A5%E8%A7%82%E5%AF%9F%E4%B8%BA%E5%9F%BA%E7%A1%80%E7%9A%84%E4%BA%8B%E5%AE%9E%E3%80%82%3C/span%3E" STYLE="fork"/>
        <node TEXT="哲学性/概念性事实：依赖于人们对自己所处世界的一些哲学性/概念性判断的事实。（这些事实能与我们的价值观拼合在一起）" ID="TTLZbzgM4f" _mubu_text="%3Cspan%20class=%22bold%22%3E%E5%93%B2%E5%AD%A6%E6%80%A7/%E6%A6%82%E5%BF%B5%E6%80%A7%E4%BA%8B%E5%AE%9E%EF%BC%9A%3C/span%3E%3Cspan%3E%E4%BE%9D%E8%B5%96%E4%BA%8E%E4%BA%BA%E4%BB%AC%E5%AF%B9%E8%87%AA%E5%B7%B1%E6%89%80%E5%A4%84%E4%B8%96%E7%95%8C%E7%9A%84%E4%B8%80%E4%BA%9B%E5%93%B2%E5%AD%A6%E6%80%A7/%E6%A6%82%E5%BF%B5%E6%80%A7%E5%88%A4%E6%96%AD%E7%9A%84%E4%BA%8B%E5%AE%9E%E3%80%82%EF%BC%88%E8%BF%99%E4%BA%9B%E4%BA%8B%E5%AE%9E%E8%83%BD%E4%B8%8E%E6%88%91%E4%BB%AC%E7%9A%84%E4%BB%B7%E5%80%BC%E8%A7%82%E6%8B%BC%E5%90%88%E5%9C%A8%E4%B8%80%E8%B5%B7%EF%BC%89%3C/span%3E" STYLE="fork"/>
        <node TEXT="连续统：连续统的一端是最明确的经验事实，另一端是最清晰的哲学性/概念性事实。（对于我们秉持的绝大多数观点，我们把其中大多数当做事实，这些事实在连续统中处于连续统的两端之间，也就是说，我们秉持这些观点的原因，一方面是有经验性的、经过直接观察得来的证据，另一方面是这些观点能与我们的整体观点拼图拼合在一起。）" ID="PBb87bamQM" _mubu_text="%3Cspan%3E%E8%BF%9E%E7%BB%AD%E7%BB%9F%EF%BC%9A%E8%BF%9E%E7%BB%AD%E7%BB%9F%E7%9A%84%E4%B8%80%E7%AB%AF%E6%98%AF%E6%9C%80%E6%98%8E%E7%A1%AE%E7%9A%84%E7%BB%8F%E9%AA%8C%E4%BA%8B%E5%AE%9E%EF%BC%8C%E5%8F%A6%E4%B8%80%E7%AB%AF%E6%98%AF%E6%9C%80%E6%B8%85%E6%99%B0%E7%9A%84%E5%93%B2%E5%AD%A6%E6%80%A7/%E6%A6%82%E5%BF%B5%E6%80%A7%E4%BA%8B%E5%AE%9E%E3%80%82%EF%BC%88%E5%AF%B9%E4%BA%8E%E6%88%91%E4%BB%AC%E7%A7%89%E6%8C%81%E7%9A%84%E7%BB%9D%E5%A4%A7%E5%A4%9A%E6%95%B0%E8%A7%82%E7%82%B9%EF%BC%8C%E6%88%91%E4%BB%AC%E6%8A%8A%E5%85%B6%E4%B8%AD%E5%A4%A7%E5%A4%9A%E6%95%B0%E5%BD%93%E5%81%9A%E4%BA%8B%E5%AE%9E%EF%BC%8C%E8%BF%99%E4%BA%9B%E4%BA%8B%E5%AE%9E%E5%9C%A8%E8%BF%9E%E7%BB%AD%E7%BB%9F%E4%B8%AD%E5%A4%84%E4%BA%8E%E8%BF%9E%E7%BB%AD%E7%BB%9F%E7%9A%84%E4%B8%A4%E7%AB%AF%E4%B9%8B%E9%97%B4%EF%BC%8C%E4%B9%9F%E5%B0%B1%E6%98%AF%E8%AF%B4%EF%BC%8C%E6%88%91%E4%BB%AC%E7%A7%89%E6%8C%81%E8%BF%99%E4%BA%9B%E8%A7%82%E7%82%B9%E7%9A%84%E5%8E%9F%E5%9B%A0%EF%BC%8C%E4%B8%80%E6%96%B9%E9%9D%A2%E6%98%AF%E6%9C%89%E7%BB%8F%E9%AA%8C%E6%80%A7%E7%9A%84%E3%80%81%E7%BB%8F%E8%BF%87%E7%9B%B4%E6%8E%A5%E8%A7%82%E5%AF%9F%E5%BE%97%E6%9D%A5%E7%9A%84%E8%AF%81%E6%8D%AE%EF%BC%8C%E5%8F%A6%E4%B8%80%E6%96%B9%E9%9D%A2%E6%98%AF%E8%BF%99%E4%BA%9B%E8%A7%82%E7%82%B9%E8%83%BD%E4%B8%8E%E6%88%91%E4%BB%AC%E7%9A%84%E6%95%B4%E4%BD%93%E8%A7%82%E7%82%B9%E6%8B%BC%E5%9B%BE%E6%8B%BC%E5%90%88%E5%9C%A8%E4%B8%80%E8%B5%B7%E3%80%82%EF%BC%89%3C/span%3E" STYLE="fork"/>
      </node>
      <node TEXT="证实与不证实证据和推理" ID="hPpx9q16ts" _mubu_text="%3Cspan%3E%E8%AF%81%E5%AE%9E%E4%B8%8E%E4%B8%8D%E8%AF%81%E5%AE%9E%E8%AF%81%E6%8D%AE%E5%92%8C%E6%8E%A8%E7%90%86%3C/span%3E" STYLE="fork">
        <node TEXT="最为直接的证据和推理模式" ID="0TlYwWwMy6" _mubu_text="%3Cspan%3E%E6%9C%80%E4%B8%BA%E7%9B%B4%E6%8E%A5%E7%9A%84%E8%AF%81%E6%8D%AE%E5%92%8C%E6%8E%A8%E7%90%86%E6%A8%A1%E5%BC%8F%3C/span%3E" STYLE="fork">
          <node TEXT="证实推理" ID="gK3aRmQRRC" _mubu_text="%3Cspan%20class=%22%20text-color-red%22%3E%E8%AF%81%E5%AE%9E%E6%8E%A8%E7%90%86%3C/span%3E" STYLE="fork">
            <node TEXT="证实推理是一种归纳推理" ID="jH3bHZ6oJe" _mubu_text="%3Cspan%3E%E8%AF%81%E5%AE%9E%E6%8E%A8%E7%90%86%E6%98%AF%E4%B8%80%E7%A7%8D%E5%BD%92%E7%BA%B3%E6%8E%A8%E7%90%86%3C/span%3E" STYLE="fork"/>
            <node TEXT="证实推理模式被广泛用于支撑科学理论的推理模式；证实推理是一种归纳推理。这就导致了严格意义上某些科学理论被认为永远都无法被证明。" ID="R7tGT7pIbU" _mubu_text="%3Cspan%3E%E8%AF%81%E5%AE%9E%E6%8E%A8%E7%90%86%E6%A8%A1%E5%BC%8F%E8%A2%AB%E5%B9%BF%E6%B3%9B%E7%94%A8%E4%BA%8E%E6%94%AF%E6%92%91%E7%A7%91%E5%AD%A6%E7%90%86%E8%AE%BA%E7%9A%84%E6%8E%A8%E7%90%86%E6%A8%A1%E5%BC%8F%EF%BC%9B%E8%AF%81%E5%AE%9E%E6%8E%A8%E7%90%86%E6%98%AF%E4%B8%80%E7%A7%8D%E5%BD%92%E7%BA%B3%E6%8E%A8%E7%90%86%E3%80%82%E8%BF%99%E5%B0%B1%E5%AF%BC%E8%87%B4%E4%BA%86%E4%B8%A5%E6%A0%BC%E6%84%8F%E4%B9%89%E4%B8%8A%E6%9F%90%E4%BA%9B%E7%A7%91%E5%AD%A6%E7%90%86%E8%AE%BA%E8%A2%AB%E8%AE%A4%E4%B8%BA%E6%B0%B8%E8%BF%9C%E9%83%BD%E6%97%A0%E6%B3%95%E8%A2%AB%E8%AF%81%E6%98%8E%E3%80%82%3C/span%3E" STYLE="fork"/>
          </node>
          <node TEXT="不证实推理" ID="uESu8dcRzJ" _mubu_text="%3Cspan%20class=%22%20text-color-red%22%3E%E4%B8%8D%E8%AF%81%E5%AE%9E%E6%8E%A8%E7%90%86%3C/span%3E" STYLE="fork">
            <node TEXT="不证实推理是一种演绎推理" ID="PmNwP8NR7V" _mubu_text="%3Cspan%3E%E4%B8%8D%E8%AF%81%E5%AE%9E%E6%8E%A8%E7%90%86%E6%98%AF%E4%B8%80%E7%A7%8D%E6%BC%94%E7%BB%8E%E6%8E%A8%E7%90%86%3C/span%3E" STYLE="fork"/>
            <node TEXT="不证实推理通常涉及大量辅助假设，因此，同不证实推理模式得出的证据只能表明，要么是所使用的理论不正确，要么是一个或者几个辅助假设不正确。" ID="OFDsHlgveN" _mubu_text="%3Cspan%3E%E4%B8%8D%E8%AF%81%E5%AE%9E%E6%8E%A8%E7%90%86%E9%80%9A%E5%B8%B8%E6%B6%89%E5%8F%8A%E5%A4%A7%E9%87%8F%E8%BE%85%E5%8A%A9%E5%81%87%E8%AE%BE%EF%BC%8C%E5%9B%A0%E6%AD%A4%EF%BC%8C%E5%90%8C%E4%B8%8D%E8%AF%81%E5%AE%9E%E6%8E%A8%E7%90%86%E6%A8%A1%E5%BC%8F%E5%BE%97%E5%87%BA%E7%9A%84%E8%AF%81%E6%8D%AE%E5%8F%AA%E8%83%BD%E8%A1%A8%E6%98%8E%EF%BC%8C%E8%A6%81%E4%B9%88%E6%98%AF%E6%89%80%3C/span%3E%3Cspan%20class=%22bold%22%3E%E4%BD%BF%E7%94%A8%E7%9A%84%E7%90%86%E8%AE%BA%E4%B8%8D%E6%AD%A3%E7%A1%AE%3C/span%3E%3Cspan%3E%EF%BC%8C%E8%A6%81%E4%B9%88%E6%98%AF%3C/span%3E%3Cspan%20class=%22bold%22%3E%E4%B8%80%E4%B8%AA%E6%88%96%E8%80%85%E5%87%A0%E4%B8%AA%E8%BE%85%E5%8A%A9%E5%81%87%E8%AE%BE%E4%B8%8D%E6%AD%A3%E7%A1%AE%3C/span%3E%3Cspan%3E%E3%80%82%3C/span%3E" STYLE="fork"/>
          </node>
        </node>
