            <node TEXT="特点：即使所有的前提条件都是真的，得出的结论也有可能是错的" ID="fwI8OSLtZP" _mubu_text="%3Cspan%3E%E7%89%B9%E7%82%B9%EF%BC%9A%E5%8D%B3%E4%BD%BF%E6%89%80%E6%9C%89%E7%9A%84%E5%89%8D%E6%8F%90%E6%9D%A1%E4%BB%B6%E9%83%BD%E6%98%AF%E7%9C%9F%E7%9A%84%EF%BC%8C%E5%BE%97%E5%87%BA%E7%9A%84%E7%BB%93%E8%AE%BA%E4%B9%9F%E6%9C%89%E5%8F%AF%E8%83%BD%E6%98%AF%E9%94%99%E7%9A%84%3C/span%3E" STYLE="fork"/>
          </node>
          <node TEXT="演绎推理" ID="kDKddUL8i7" _mubu_text="%3Cspan%20class=%22%20text-color-red%22%3E%E6%BC%94%E7%BB%8E%E6%8E%A8%E7%90%86%3C/span%3E" STYLE="fork">
            <node TEXT="特点：真的前提条件就保证了真的结论。" ID="b8dIYq7skz" _mubu_text="%3Cspan%3E%E7%89%B9%E7%82%B9%EF%BC%9A%E7%9C%9F%E7%9A%84%E5%89%8D%E6%8F%90%E6%9D%A1%E4%BB%B6%E5%B0%B1%E4%BF%9D%E8%AF%81%E4%BA%86%E7%9C%9F%E7%9A%84%E7%BB%93%E8%AE%BA%E3%80%82%3C/span%3E" STYLE="fork">
              <node TEXT="实际上目前我认为（2025.5.4），就算是演绎推理严格意义上也不一定就是对的：1. 前提条件为真的范围太小，能够用来在此基础上进行知识架构的真理太少。经验事实受表征理论所困，概念性事实受价值观所困。 2. 演绎推理本身是否又有问题，难道说演绎推理本身算得上绝对真理吗？其次演绎推理本身也有可能是由归纳推理得出的。" ID="lKPD3HmwLE" _mubu_text="%3Cspan%20class=%22italic%22%3E%E5%AE%9E%E9%99%85%E4%B8%8A%E7%9B%AE%E5%89%8D%E6%88%91%E8%AE%A4%E4%B8%BA%EF%BC%882025.5.4%EF%BC%89%EF%BC%8C%E5%B0%B1%E7%AE%97%E6%98%AF%E6%BC%94%E7%BB%8E%E6%8E%A8%E7%90%86%E4%B8%A5%E6%A0%BC%E6%84%8F%E4%B9%89%E4%B8%8A%E4%B9%9F%E4%B8%8D%E4%B8%80%E5%AE%9A%E5%B0%B1%E6%98%AF%E5%AF%B9%E7%9A%84%EF%BC%9A1.%20%E5%89%8D%E6%8F%90%E6%9D%A1%E4%BB%B6%E4%B8%BA%E7%9C%9F%E7%9A%84%E8%8C%83%E5%9B%B4%E5%A4%AA%E5%B0%8F%EF%BC%8C%E8%83%BD%E5%A4%9F%E7%94%A8%E6%9D%A5%E5%9C%A8%E6%AD%A4%E5%9F%BA%E7%A1%80%E4%B8%8A%E8%BF%9B%E8%A1%8C%E7%9F%A5%E8%AF%86%E6%9E%B6%E6%9E%84%E7%9A%84%E7%9C%9F%E7%90%86%E5%A4%AA%E5%B0%91%E3%80%82%E7%BB%8F%E9%AA%8C%E4%BA%8B%E5%AE%9E%E5%8F%97%E8%A1%A8%E5%BE%81%E7%90%86%E8%AE%BA%E6%89%80%E5%9B%B0%EF%BC%8C%E6%A6%82%E5%BF%B5%E6%80%A7%E4%BA%8B%E5%AE%9E%E5%8F%97%E4%BB%B7%E5%80%BC%E8%A7%82%E6%89%80%E5%9B%B0%E3%80%82%202.%20%E6%BC%94%E7%BB%8E%E6%8E%A8%E7%90%86%E6%9C%AC%E8%BA%AB%E6%98%AF%E5%90%A6%E5%8F%88%E6%9C%89%E9%97%AE%E9%A2%98%EF%BC%8C%E9%9A%BE%E9%81%93%E8%AF%B4%E6%BC%94%E7%BB%8E%E6%8E%A8%E7%90%86%E6%9C%AC%E8%BA%AB%E7%AE%97%E5%BE%97%E4%B8%8A%E7%BB%9D%E5%AF%B9%E7%9C%9F%E7%90%86%E5%90%97%EF%BC%9F%E5%85%B6%E6%AC%A1%E6%BC%94%E7%BB%8E%E6%8E%A8%E7%90%86%E6%9C%AC%E8%BA%AB%E4%B9%9F%E6%9C%89%E5%8F%AF%E8%83%BD%E6%98%AF%E7%94%B1%E5%BD%92%E7%BA%B3%E6%8E%A8%E7%90%86%E5%BE%97%E5%87%BA%E7%9A%84%E3%80%82%3C/span%3E" STYLE="fork"/>
            </node>
          </node>
        </node>
      </node>
      <node TEXT="奎因-迪昂论点和对科学方法的意义" ID="znSXeN1w1d" _mubu_text="%3Cspan%3E%E5%A5%8E%E5%9B%A0-%E8%BF%AA%E6%98%82%E8%AE%BA%E7%82%B9%E5%92%8C%E5%AF%B9%E7%A7%91%E5%AD%A6%E6%96%B9%E6%B3%95%E7%9A%84%E6%84%8F%E4%B9%89%3C/span%3E" STYLE="fork">
        <node TEXT="奎因-迪昂论点" ID="BLAriyrVKz" _mubu_text="%3Cspan%3E%E5%A5%8E%E5%9B%A0-%E8%BF%AA%E6%98%82%E8%AE%BA%E7%82%B9%3C/span%3E" STYLE="fork">
          <node TEXT="三个关键点" ID="R1nBgp4z3B" _mubu_text="%3Cspan%3E%E4%B8%89%E4%B8%AA%E5%85%B3%E9%94%AE%E7%82%B9%3C/span%3E" STYLE="fork">
            <node TEXT="1. 我们的观点并不是单独而是作为整体来面对”经验的裁判“" ID="2RNTxQz7nv" _mubu_text="%3Cspan%3E1.%20%E6%88%91%E4%BB%AC%E7%9A%84%E8%A7%82%E7%82%B9%E5%B9%B6%E4%B8%8D%E6%98%AF%E5%8D%95%E7%8B%AC%E8%80%8C%E6%98%AF%E4%BD%9C%E4%B8%BA%E6%95%B4%E4%BD%93%E6%9D%A5%E9%9D%A2%E5%AF%B9%E2%80%9D%E7%BB%8F%E9%AA%8C%E7%9A%84%E8%A3%81%E5%88%A4%E2%80%9C%3C/span%3E" STYLE="fork">
              <node TEXT="奎因认为我们整个内部相互联结的观点集合作为一个整体来面对经验的裁判。如果面对与我们所持观点相悖的证据，那么任何观点包括核心观点都不可能免受修改。" ID="BWmQZ4ScIM" _mubu_text="%3Cspan%20class=%22bold%22%3E%E5%A5%8E%E5%9B%A0%3C/span%3E%3Cspan%3E%E8%AE%A4%E4%B8%BA%E6%88%91%E4%BB%AC%3C/span%3E%3Cspan%20class=%22bold%22%3E%E6%95%B4%E4%B8%AA%E5%86%85%E9%83%A8%E7%9B%B8%E4%BA%92%E8%81%94%E7%BB%93%E7%9A%84%E8%A7%82%E7%82%B9%E9%9B%86%E5%90%88%3C/span%3E%3Cspan%3E%E4%BD%9C%E4%B8%BA%E4%B8%80%E4%B8%AA%E6%95%B4%E4%BD%93%E6%9D%A5%E9%9D%A2%E5%AF%B9%E7%BB%8F%E9%AA%8C%E7%9A%84%E8%A3%81%E5%88%A4%E3%80%82%E5%A6%82%E6%9E%9C%E9%9D%A2%E5%AF%B9%E4%B8%8E%E6%88%91%E4%BB%AC%E6%89%80%E6%8C%81%E8%A7%82%E7%82%B9%E7%9B%B8%E6%82%96%E7%9A%84%E8%AF%81%E6%8D%AE%EF%BC%8C%E9%82%A3%E4%B9%88%3C/span%3E%3Cspan%20class=%22bold%22%3E%E4%BB%BB%E4%BD%95%E8%A7%82%E7%82%B9%E5%8C%85%E6%8B%AC%E6%A0%B8%E5%BF%83%E8%A7%82%E7%82%B9%E9%83%BD%E4%B8%8D%E5%8F%AF%E8%83%BD%E5%85%8D%E5%8F%97%E4%BF%AE%E6%94%B9%3C/span%3E%3Cspan%3E%E3%80%82%3C/span%3E" STYLE="fork"/>
              <node TEXT="迪昂的观点则更保守，他认为验证可能涉及一个观点数量众多的观点集合，但通常这个验证所针对的并不是我们整体的观点集合，或者我们整体的世界观。" ID="vdRV9FPthT" _mubu_text="%3Cspan%20class=%22bold%22%3E%E8%BF%AA%E6%98%82%3C/span%3E%3Cspan%3E%E7%9A%84%E8%A7%82%E7%82%B9%E5%88%99%E6%9B%B4%E4%BF%9D%E5%AE%88%EF%BC%8C%E4%BB%96%E8%AE%A4%E4%B8%BA%E9%AA%8C%E8%AF%81%E5%8F%AF%E8%83%BD%E6%B6%89%E5%8F%8A%E4%B8%80%E4%B8%AA%E8%A7%82%E7%82%B9%E6%95%B0%E9%87%8F%E4%BC%97%E5%A4%9A%E7%9A%84%E8%A7%82%E7%82%B9%E9%9B%86%E5%90%88%EF%BC%8C%E4%BD%86%E9%80%9A%E5%B8%B8%E8%BF%99%E4%B8%AA%E9%AA%8C%E8%AF%81%E6%89%80%E9%92%88%E5%AF%B9%E7%9A%84%E5%B9%B6%3C/span%3E%3Cspan%20class=%22bold%22%3E%E4%B8%8D%E6%98%AF%E6%88%91%E4%BB%AC%E6%95%B4%E4%BD%93%E7%9A%84%E8%A7%82%E7%82%B9%E9%9B%86%E5%90%88%3C/span%3E%3Cspan%3E%EF%BC%8C%E6%88%96%E8%80%85%E6%88%91%E4%BB%AC%E6%95%B4%E4%BD%93%E7%9A%84%E4%B8%96%E7%95%8C%E8%A7%82%E3%80%82%3C/span%3E" STYLE="fork"/>
            </node>
            <node TEXT="2. 通常不存在可以用来判断两个竞争理论中哪一个正确的“判决性实验“" ID="P626vDptdg" _mubu_text="%3Cspan%3E2.%20%E9%80%9A%E5%B8%B8%E4%B8%8D%E5%AD%98%E5%9C%A8%E5%8F%AF%E4%BB%A5%E7%94%A8%E6%9D%A5%E5%88%A4%E6%96%AD%E4%B8%A4%E4%B8%AA%E7%AB%9E%E4%BA%89%E7%90%86%E8%AE%BA%E4%B8%AD%E5%93%AA%E4%B8%80%E4%B8%AA%E6%AD%A3%E7%A1%AE%E7%9A%84%E2%80%9C%E5%88%A4%E5%86%B3%E6%80%A7%E5%AE%9E%E9%AA%8C%E2%80%9C%3C/span%3E" STYLE="fork">
              <node TEXT="判决性实验：但面对两个相互竞争的理论时，有可能设计出一个实验，关于这个实验的结果，两个理论的预言是相互矛盾的，这样一个实验至少可以证明其中一个理论是错误的。" ID="toAQRCmEat" _mubu_text="%3Cspan%20class=%22bold%22%3E%E5%88%A4%E5%86%B3%E6%80%A7%E5%AE%9E%E9%AA%8C%EF%BC%9A%3C/span%3E%3Cspan%3E%E4%BD%86%E9%9D%A2%E5%AF%B9%E4%B8%A4%E4%B8%AA%3C/span%3E%3Cspan%20class=%22bold%22%3E%E7%9B%B8%E4%BA%92%E7%AB%9E%E4%BA%89%E7%9A%84%E7%90%86%E8%AE%BA%3C/span%3E%3Cspan%3E%E6%97%B6%EF%BC%8C%E6%9C%89%E5%8F%AF%E8%83%BD%E8%AE%BE%E8%AE%A1%E5%87%BA%E4%B8%80%E4%B8%AA%E5%AE%9E%E9%AA%8C%EF%BC%8C%E5%85%B3%E4%BA%8E%E8%BF%99%E4%B8%AA%E5%AE%9E%E9%AA%8C%E7%9A%84%E7%BB%93%E6%9E%9C%EF%BC%8C%3C/span%3E%3Cspan%20class=%22bold%22%3E%E4%B8%A4%E4%B8%AA%E7%90%86%E8%AE%BA%E7%9A%84%E9%A2%84%E8%A8%80%E6%98%AF%E7%9B%B8%E4%BA%92%E7%9F%9B%E7%9B%BE%E7%9A%84%3C/span%3E%3Cspan%3E%EF%BC%8C%E8%BF%99%E6%A0%B7%E4%B8%80%E4%B8%AA%E5%AE%9E%E9%AA%8C%E8%87%B3%E5%B0%91%E5%8F%AF%E4%BB%A5%3C/span%3E%3Cspan%20class=%22bold%22%3E%E8%AF%81%E6%98%8E%E5%85%B6%E4%B8%AD%E4%B8%80%E4%B8%AA%E7%90%86%E8%AE%BA%E6%98%AF%E9%94%99%E8%AF%AF%3C/span%3E%3Cspan%3E%E7%9A%84%E3%80%82%3C/span%3E" STYLE="fork"/>
              <node TEXT="奎因-迪昂论点涉及对于“判决性实验”的某种怀疑论。在任何一个这样的实验中，做出错误预言的理论任然可以保留，所要摒弃的只是某个辅助假设。从某种意义上来说，这一观点大体上被认为是正确的，也就是说，会出现这种无法设计出一个关键，来确定两个相互竞争理论中哪个才正确的情况。有另一个表述：“实验结果，不管是什么，都可以与任意一个理论相适应”，还没有形成共识。" ID="DI4iF6q8El" _mubu_text="%3Cspan%3E%E5%A5%8E%E5%9B%A0-%E8%BF%AA%E6%98%82%E8%AE%BA%E7%82%B9%E6%B6%89%E5%8F%8A%E5%AF%B9%E4%BA%8E%E2%80%9C%E5%88%A4%E5%86%B3%E6%80%A7%E5%AE%9E%E9%AA%8C%E2%80%9D%E7%9A%84%E6%9F%90%E7%A7%8D%E6%80%80%E7%96%91%E8%AE%BA%E3%80%82%E5%9C%A8%E4%BB%BB%E4%BD%95%E4%B8%80%E4%B8%AA%E8%BF%99%E6%A0%B7%E7%9A%84%E5%AE%9E%E9%AA%8C%E4%B8%AD%EF%BC%8C%E5%81%9A%E5%87%BA%E9%94%99%E8%AF%AF%E9%A2%84%E8%A8%80%E7%9A%84%E7%90%86%E8%AE%BA%E4%BB%BB%E7%84%B6%E5%8F%AF%E4%BB%A5%E4%BF%9D%E7%95%99%EF%BC%8C%E6%89%80%E8%A6%81%E6%91%92%E5%BC%83%E7%9A%84%E5%8F%AA%E6%98%AF%E6%9F%90%E4%B8%AA%E8%BE%85%E5%8A%A9%E5%81%87%E8%AE%BE%E3%80%82%E4%BB%8E%E6%9F%90%E7%A7%8D%E6%84%8F%E4%B9%89%E4%B8%8A%E6%9D%A5%E8%AF%B4%EF%BC%8C%E8%BF%99%E4%B8%80%E8%A7%82%E7%82%B9%E5%A4%A7%E4%BD%93%E4%B8%8A%E8%A2%AB%E8%AE%A4%E4%B8%BA%E6%98%AF%E6%AD%A3%E7%A1%AE%E7%9A%84%EF%BC%8C%E4%B9%9F%E5%B0%B1%E6%98%AF%E8%AF%B4%EF%BC%8C%E4%BC%9A%E5%87%BA%E7%8E%B0%E8%BF%99%E7%A7%8D%E6%97%A0%E6%B3%95%E8%AE%BE%E8%AE%A1%E5%87%BA%E4%B8%80%E4%B8%AA%E5%85%B3%E9%94%AE%EF%BC%8C%E6%9D%A5%E7%A1%AE%E5%AE%9A%E4%B8%A4%E4%B8%AA%E7%9B%B8%E4%BA%92%E7%AB%9E%E4%BA%89%E7%90%86%E8%AE%BA%E4%B8%AD%E5%93%AA%E4%B8%AA%E6%89%8D%E6%AD%A3%E7%A1%AE%E7%9A%84%E6%83%85%E5%86%B5%E3%80%82%E6%9C%89%E5%8F%A6%E4%B8%80%E4%B8%AA%E8%A1%A8%E8%BF%B0%EF%BC%9A%E2%80%9C%E5%AE%9E%E9%AA%8C%E7%BB%93%E6%9E%9C%EF%BC%8C%E4%B8%8D%E7%AE%A1%E6%98%AF%E4%BB%80%E4%B9%88%EF%BC%8C%E9%83%BD%E5%8F%AF%E4%BB%A5%E4%B8%8E%E4%BB%BB%E6%84%8F%E4%B8%80%E4%B8%AA%E7%90%86%E8%AE%BA%E7%9B%B8%E9%80%82%E5%BA%94%E2%80%9D%EF%BC%8C%E8%BF%98%E6%B2%A1%E6%9C%89%E5%BD%A2%E6%88%90%E5%85%B1%E8%AF%86%E3%80%82%3C/span%3E" STYLE="fork"/>
              <node TEXT="我目前认为（2025.5.5），要想设计出一个”判决性实验“是不太可能的，但是在这里设计实验时，要注意的是主要假设和辅助假设都得置于一个全局中。但是这样的实验和验证在某个严格意义条件上的实验结果是否符合预期的实验几乎没有区别。因为我们所设计实验的另一个竞争性实验，它与所设计的实验是对立的关系，我们几乎无法设计出这样一个实验，因为不仅是主要假设是可能无限多的，辅助假设也可能是无限多的。我们只能判断我们所设计的实验的所有条件和主要假设是否符合预期，但无法去确定其他实验的正确与否。因为：1. 其他实验无限多 2. 有时人类受限于所接触的常识，对于有些东西是想象也难以想象出来，也就导致有时我们认为是对立的，实际上并不是对立的，而且我们有时以为能放到一个层面去考虑的东西，实际上它是多层覆盖的。比如：很早之前人们不会认为波粒二象性是正确的。就像二维生物对三维生物。" ID="GiDQnTZa6f" _mubu_text="%3Cspan%20class=%22italic%22%3E%E6%88%91%E7%9B%AE%E5%89%8D%E8%AE%A4%E4%B8%BA%EF%BC%882025.5.5%EF%BC%89%EF%BC%8C%E8%A6%81%E6%83%B3%E8%AE%BE%E8%AE%A1%E5%87%BA%E4%B8%80%E4%B8%AA%E2%80%9D%E5%88%A4%E5%86%B3%E6%80%A7%E5%AE%9E%E9%AA%8C%E2%80%9C%E6%98%AF%E4%B8%8D%E5%A4%AA%E5%8F%AF%E8%83%BD%E7%9A%84%EF%BC%8C%E4%BD%86%E6%98%AF%E5%9C%A8%E8%BF%99%E9%87%8C%E8%AE%BE%E8%AE%A1%E5%AE%9E%E9%AA%8C%E6%97%B6%EF%BC%8C%E8%A6%81%E6%B3%A8%E6%84%8F%E7%9A%84%E6%98%AF%E4%B8%BB%E8%A6%81%E5%81%87%E8%AE%BE%E5%92%8C%E8%BE%85%E5%8A%A9%E5%81%87%E8%AE%BE%E9%83%BD%E5%BE%97%E7%BD%AE%E4%BA%8E%E4%B8%80%E4%B8%AA%E5%85%A8%E5%B1%80%E4%B8%AD%E3%80%82%E4%BD%86%E6%98%AF%E8%BF%99%E6%A0%B7%E7%9A%84%E5%AE%9E%E9%AA%8C%E5%92%8C%E9%AA%8C%E8%AF%81%E5%9C%A8%E6%9F%90%E4%B8%AA%E4%B8%A5%E6%A0%BC%E6%84%8F%E4%B9%89%E6%9D%A1%E4%BB%B6%E4%B8%8A%E7%9A%84%E5%AE%9E%E9%AA%8C%E7%BB%93%E6%9E%9C%E6%98%AF%E5%90%A6%E7%AC%A6%E5%90%88%E9%A2%84%E6%9C%9F%E7%9A%84%E5%AE%9E%E9%AA%8C%E5%87%A0%E4%B9%8E%E6%B2%A1%E6%9C%89%E5%8C%BA%E5%88%AB%E3%80%82%E5%9B%A0%E4%B8%BA%E6%88%91%E4%BB%AC%E6%89%80%E8%AE%BE%E8%AE%A1%E5%AE%9E%E9%AA%8C%E7%9A%84%E5%8F%A6%E4%B8%80%E4%B8%AA%E7%AB%9E%E4%BA%89%E6%80%A7%E5%AE%9E%E9%AA%8C%EF%BC%8C%E5%AE%83%E4%B8%8E%E6%89%80%E8%AE%BE%E8%AE%A1%E7%9A%84%E5%AE%9E%E9%AA%8C%E6%98%AF%E5%AF%B9%E7%AB%8B%E7%9A%84%E5%85%B3%E7%B3%BB%EF%BC%8C%E6%88%91%E4%BB%AC%E5%87%A0%E4%B9%8E%E6%97%A0%E6%B3%95%E8%AE%BE%E8%AE%A1%E5%87%BA%E8%BF%99%E6%A0%B7%E4%B8%80%E4%B8%AA%E5%AE%9E%E9%AA%8C%EF%BC%8C%E5%9B%A0%E4%B8%BA%E4%B8%8D%E4%BB%85%E6%98%AF%E4%B8%BB%E8%A6%81%E5%81%87%E8%AE%BE%E6%98%AF%E5%8F%AF%E8%83%BD%E6%97%A0%E9%99%90%E5