            <node TEXT="3. 非充分决定性的概念，也就是现有可用的数据，通常不足以让人么找到唯一正确的理论" ID="lhZMUcb5ml" _mubu_text="%3Cspan%3E3.%20%E9%9D%9E%E5%85%85%E5%88%86%E5%86%B3%E5%AE%9A%E6%80%A7%E7%9A%84%E6%A6%82%E5%BF%B5%EF%BC%8C%E4%B9%9F%E5%B0%B1%E6%98%AF%E7%8E%B0%E6%9C%89%E5%8F%AF%E7%94%A8%E7%9A%84%E6%95%B0%E6%8D%AE%EF%BC%8C%E9%80%9A%E5%B8%B8%E4%B8%8D%E8%B6%B3%E4%BB%A5%E8%AE%A9%E4%BA%BA%E4%B9%88%E6%89%BE%E5%88%B0%E5%94%AF%E4%B8%80%E6%AD%A3%E7%A1%AE%E7%9A%84%E7%90%86%E8%AE%BA%3C/span%3E" STYLE="fork"/>
